import geometry;

unitsize(1 cm);

pair A, B, C, I, M, N;

A = (1,3);
B = (0,0);
C = (4,0);
I = incenter(A,B,C);
M = extension(I, I + B - C, A, B);
N = extension(I, I + B - C, A, C);

draw(A--B--C--cycle);
draw(B--I--C);
draw(M--N);

label("$A$", A, dir(90));
label("$B$", B, SW);
label("$C$", C, SE);
label("$I$", I, dir(90));
label("$M$", M, NW);
label("$N$", N, NE);
[/asy]

